/**
 * Webhook notification handler — dispatches HTTP callbacks to registered
 * URLs when order events occur.
 *
 * Subscribes to order events through the EventBus and fires webhooks
 * to external URLs, following the same event-driven pattern used by
 * the EmailNotificationHandler and NotificationService.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 * - NotificationService for recording webhook notifications
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationService } from '../services/notification.service.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  createdAt: Date;
}

export interface WebhookPayload {
  webhookId: string;
  eventType: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export interface WebhookDeliveryResult {
  webhookId: string;
  url: string;
  success: boolean;
  statusCode?: number;
  error?: string;
}

/**
 * Function type for sending HTTP requests. Defaults to global fetch,
 * but can be replaced in tests.
 */
export type HttpPostFn = (url: string, body: string) => Promise<{ status: number }>;

let nextWebhookId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextWebhookId = 1;
}

export class WebhookNotificationHandler {
  private logger = new Logger('WebhookNotificationHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveryLog: WebhookDeliveryResult[] = [];
  private httpPost: HttpPostFn;

  constructor(
    private eventBus: EventBus,
    private notificationService: NotificationService,
    httpPost?: HttpPostFn,
  ) {
    this.httpPost = httpPost ?? defaultHttpPost;
    this.registerHandlers();
  }

  /**
   * Register event handlers for webhook triggers.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  registerWebhook(url: string, eventType: EventType): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Registered webhook ${registration.id} for ${eventType} -> ${url}`);
    return registration;
  }

  /**
   * Unregister a webhook by its ID.
   */
  unregisterWebhook(webhookId: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === webhookId);
    if (index < 0) {
      return false;
    }
    this.registrations.splice(index, 1);
    this.logger.info(`Unregistered webhook ${webhookId}`);
    return true;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registered webhooks for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get the delivery log (useful for testing and debugging).
   */
  getDeliveryLog(): WebhookDeliveryResult[] {
    return [...this.deliveryLog];
  }

  /**
   * Clear all registrations and delivery log (useful for testing).
   */
  clear(): void {
    this.registrations = [];
    this.deliveryLog = [];
  }

  /**
   * Handle order created — fire webhooks registered for this event.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const payload: WebhookPayload = {
      webhookId: '',
      eventType: 'order:created',
      timestamp: event.timestamp.toISOString(),
      data: {
        orderId: event.order.id,
        userId: event.order.userId,
        items: event.order.items,
        total: event.order.total,
        status: event.order.status,
      },
    };

    await this.fireWebhooks('order:created', payload);
  }

  /**
   * Handle order status change — fire webhooks registered for this event.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    const payload: WebhookPayload = {
      webhookId: '',
      eventType: 'order:status-changed',
      timestamp: event.timestamp.toISOString(),
      data: {
        orderId: event.order.id,
        userId: event.order.userId,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    };

    await this.fireWebhooks('order:status-changed', payload);
  }

  /**
   * Fire all registered webhooks for a given event type.
   */
  private async fireWebhooks(eventType: EventType, payload: WebhookPayload): Promise<void> {
    const webhooks = this.getRegistrationsForEvent(eventType);

    for (const webhook of webhooks) {
      const webhookPayload = { ...payload, webhookId: webhook.id };
      const result = await this.deliverWebhook(webhook, webhookPayload);
      this.deliveryLog.push(result);

      this.notificationService.recordNotification({
        channel: 'in-app',
        recipient: webhook.url,
        subject: `Webhook ${result.success ? 'delivered' : 'failed'}: ${eventType}`,
        body: JSON.stringify(webhookPayload),
      });
    }
  }

  /**
   * Deliver a single webhook — POST the payload to the registered URL.
   */
  private async deliverWebhook(
    webhook: WebhookRegistration,
    payload: WebhookPayload,
  ): Promise<WebhookDeliveryResult> {
    try {
      this.logger.info(`Delivering webhook ${webhook.id} to ${webhook.url}`);
      const response = await this.httpPost(webhook.url, JSON.stringify(payload));

      const success = response.status >= 200 && response.status < 300;
      return {
        webhookId: webhook.id,
        url: webhook.url,
        success,
        statusCode: response.status,
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Webhook ${webhook.id} delivery failed: ${message}`);
      return {
        webhookId: webhook.id,
        url: webhook.url,
        success: false,
        error: message,
      };
    }
  }
}

/**
 * Default HTTP POST implementation using global fetch.
 */
async function defaultHttpPost(url: string, body: string): Promise<{ status: number }> {
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body,
  });
  return { status: response.status };
}

