import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  WebhookNotificationHandler,
  resetWebhookIdCounter,
} from '../../src/notifications/webhook-notification.handler.js';
import type { HttpPostFn } from '../../src/notifications/webhook-notification.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
    ...overrides,
  };
}

describe('WebhookNotificationHandler', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let handler: WebhookNotificationHandler;
  let mockPost: HttpPostFn;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    resetNotificationIdCounter();
    resetWebhookIdCounter();
    mockPost = vi.fn().mockResolvedValue({ status: 200 });
    handler = new WebhookNotificationHandler(eventBus, notificationService, mockPost);
  });

  describe('webhook registration', () => {
    it('should register a webhook and return a registration', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should generate sequential webhook IDs', () => {
      const reg1 = handler.registerWebhook('https://a.com/hook', 'order:created');
      const reg2 = handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(reg1.id).toBe('webhook-0001');
      expect(reg2.id).toBe('webhook-0002');
    });

    it('should list all registrations', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');
      handler.registerWebhook('https://c.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook('https://a.com/hook', 'order:created');

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  describe('order:created webhook delivery', () => {
    it('should fire webhook when order:created event is emitted', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockPost).toHaveBeenCalledOnce();
      const [url, body] = (mockPost as ReturnType<typeof vi.fn>).mock.calls[0] as [string, string];
      expect(url).toBe('https://example.com/hook');

      const payload = JSON.parse(body);
      expect(payload.eventType).toBe('order:created');
      expect(payload.webhookId).toBe('webhook-0001');
      expect(payload.data.orderId).toBe('order-1');
      expect(payload.data.total).toBe(20);
    });

    it('should fire multiple webhooks for the same event type', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockPost).toHaveBeenCalledTimes(2);
    });

    it('should not fire webhooks registered for a different event type', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockPost).not.toHaveBeenCalled();
    });

    it('should record delivery results in the delivery log', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const log = handler.getDeliveryLog();
      expect(log).toHaveLength(1);
      expect(log[0]?.webhookId).toBe('webhook-0001');
      expect(log[0]?.url).toBe('https://example.com/hook');
      expect(log[0]?.success).toBe(true);
      expect(log[0]?.statusCode).toBe(200);
    });

    it('should record notification via NotificationService', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      // NotificationService gets: 1 from its own order:created handler + 1 from webhook
      const all = notificationService.getNotifications();
      const webhookNotification = all.find((n) => n.subject.includes('Webhook delivered'));
      expect(webhookNotification).toBeDefined();
      expect(webhookNotification?.recipient).toBe('https://example.com/hook');
    });
  });

  describe('order:status-changed webhook delivery', () => {
    it('should fire webhook when order:status-changed event is emitted', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent());

      expect(mockPost).toHaveBeenCalledOnce();
      const [, body] = (mockPost as ReturnType<typeof vi.fn>).mock.calls[0] as [string, string];
      const payload = JSON.parse(body);
      expect(payload.eventType).toBe('order:status-changed');
      expect(payload.data.previousStatus).toBe('pending');
      expect(payload.data.newStatus).toBe('confirmed');
    });
  });

  describe('error handling', () => {
    it('should handle HTTP errors gracefully', async () => {
      mockPost = vi.fn().mockResolvedValue({ status: 500 });
      handler = new WebhookNotificationHandler(eventBus, notificationService, mockPost);
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const log = handler.getDeliveryLog();
      expect(log).toHaveLength(1);
      expect(log[0]?.success).toBe(false);
      expect(log[0]?.statusCode).toBe(500);
    });

    it('should handle network failures gracefully', async () => {
      mockPost = vi.fn().mockRejectedValue(new Error('Connection refused'));
      handler = new WebhookNotificationHandler(eventBus, notificationService, mockPost);
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const log = handler.getDeliveryLog();
      expect(log).toHaveLength(1);
      expect(log[0]?.success).toBe(false);
      expect(log[0]?.error).toBe('Connection refused');
    });

    it('should record failed webhook notification via NotificationService', async () => {
      mockPost = vi.fn().mockRejectedValue(new Error('timeout'));
      handler = new WebhookNotificationHandler(eventBus, notificationService, mockPost);
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const all = notificationService.getNotifications();
      const failedNotification = all.find((n) => n.subject.includes('Webhook failed'));
      expect(failedNotification).toBeDefined();
    });
  });

  describe('clear', () => {
    it('should clear registrations and delivery log', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clear();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveryLog()).toHaveLength(0);
    });

    it('should not fire webhooks after clearing registrations', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      handler.clear();

      await eventBus.emit(makeOrderCreatedEvent());

      // mockPost should not be called for webhooks (only the NotificationService handler fires)
      expect(mockPost).not.toHaveBeenCalled();
    });
  });
});

