+        body: JSON.stringify(webhookPayload),
+      });
+    }
+  }
+
+  /**
+   * Deliver a single webhook — POST the payload to the registered URL.
+   */
+  private async deliverWebhook(
+    webhook: WebhookRegistration,
+    payload: WebhookPayload,
+  ): Promise<WebhookDeliveryResult> {
+    try {
+      this.logger.info(`Delivering webhook ${webhook.id} to ${webhook.url}`);
+      const response = await this.httpPost(webhook.url, JSON.stringify(payload));
+
+      const success = response.status >= 200 && response.status < 300;
+      return {
+        webhookId: webhook.id,
+        url: webhook.url,
+        success,
+        statusCode: response.status,
+      };
+    } catch (error) {
+      const message = error instanceof Error ? error.message : String(error);
+      this.logger.error(`Webhook ${webhook.id} delivery failed: ${message}`);
+      return {
+        webhookId: webhook.id,
+        url: webhook.url,
+        success: false,
+        error: message,
+      };
+    }
+  }
+}
+
+/**
+ * Default HTTP POST implementation using global fetch (Node 18+).
+ */
+// eslint-disable-next-line @typescript-eslint/no-explicit-any
+declare const fetch: (input: string, init?: any) => Promise<{ status: number }>;
+
+async function defaultHttpPost(url: string, body: string): Promise<{ status: number }> {
+  const response = await fetch(url, {
+    method: 'POST',
+    headers: { 'Content-Type': 'application/json' },
+    body,
+  });
+  return { status: response.status };
+}

